schema.ddl:
CREATE TABLE devicetelemetry (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  businessId uuid NOT NULL,
  eventId uuid UNIQUE,
  correlationId uuid,
  status text NOT NULL,
  statusVersion integer NOT NULL,
  status text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_devicetelemetry_businessId ON devicetelemetry (businessId);

CREATE INDEX idx_devicetelemetry_correlationId ON devicetelemetry (correlationId);

CREATE TABLE devicetelemetry_step_log (
  id bigserial PRIMARY KEY,
  devicetelemetry_id uuid NOT NULL,
  step text NOT NULL,
  status text NOT NULL,
  details jsonb,
  occurred_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_devicetelemetry_step_log_ref ON devicetelemetry_step_log (devicetelemetry_id);

CREATE TABLE outbox (
  id bigserial PRIMARY KEY,
  aggregate_id uuid NOT NULL,
  event_type text NOT NULL,
  payload jsonb NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  published_at timestamptz
);

CREATE INDEX idx_outbox_unpublished ON outbox (id) WHERE published_at IS NULL;
